/*
 * App — root XComponent / Fragment generated by the editor.
 * Container (0385) instantiates this class first, then reads
 * `loaderData` and `entryPointData` off the resolved instance
 * to drive the rest of boot.
 *
 * Editor-bound configuration (set after all child fragments
 * report `__ready`):
 *   - `loaderData = { fragment: 'LoaderView', assets: 'shaders, uil' }`
 *     Container reads these to (a) instantiate `LoaderView` as
 *     the loading overlay, and (b) filter the AssetLoader to
 *     just the shaders+uil buckets initially (rest stream in
 *     later).
 *   - `entryPointData = 'ViewController'` — class to mount
 *     once load completes.
 *
 * Child fragments declared in the editor graph (only one here):
 *   - `ref_XRConfig141` — XRConfig fragment with `multiview:
 *     'false'`. Disables multiview at boot for this build (web
 *     target lacks Oculus multiview anyway).
 *
 * The `for (key in self)` promise-unwrap and `__ready` flag is
 * the standard fragment-init pattern: every property whose
 * value is a Promise resolves into the property slot once the
 * child class finishes booting.
 */
Class(function App() {
  const self = this;
  Inherit(self, Component);
  Inherit(self, XComponent);
  self.fragName = 'App';
  self.contexts = 'Component';
  this.isFragment = true;
  var _promises = [];
  !(async function () {
    self.element && (self.element.onMountedHook = (_) => self.onMounted?.());
    self.ref_XRConfig141 = self.initClass(
      XRConfig,
      AppState.createLocal(
        {
          multiview: 'false',
        },
        true,
      ),
    );
    self.ref_XRConfig141.isFragment && _promises.push(self.wait(self.ref_XRConfig141, '__ready'));
    self.parent?.layers && (self.layers = self.parent.layers);
    self.layout?.getAllLayers && (self.layers = await self.layout.getAllLayers());
    for (let key in self)
      if (self[key]?.then) {
        let store = self[key];
        store.then((val) => (self[key] = val));
        _promises.push(store);
      }
    _promises.length && (await Promise.all(_promises));
    self.loaderData = {
      fragment: 'LoaderView',
      assets: 'shaders, uil',
    };
    self.entryPointData = 'ViewController';
    _promises = null;
    self.flag?.('__ready', true);
    self.onInit?.();
  })();
});
